INSERT INTO runpsy_articles (slug, title, description, date, author_slug, category_slug, tags, reading_time, seo_title, seo_description, status, intent, cta, safety_note, related_slugs, introduction, insight_impulse, sections, faq, quiz, sort_order) VALUES

-- Статья 1: Почему партнёр отдаляется
('pochemu-partner-otdalyaetsya',
 'Почему партнёр отдаляется: механизмы потери интереса',
 'Потеря интереса — это следствие рутины и растворения личных границ. Ваш мозг привык к партнеру, и дофамин перестал выделяться.',
 '2026-05-03',
 'runpsy-editorial-team',
 'relationships',
 '["потеря интереса","дофамин","дистанция","слияние"]',
 '8 мин',
 'Почему партнёр отдаляется: механизмы потери интереса | RunPsy',
 'Разбираем нейробиологию потери интереса в отношениях. Почему партнёр отдаляется и что с этим делать.',
 'published',
 'эмоциональный',
 'Запланируйте на вечер занятие исключительно для себя. Не рассказывайте партнеру в деталях, чем именно будете заниматься.',
 'Если отдаление превращается в тотальный бойкот (игнорирование неделями) и вызывает у вас панические атаки.',
 '["kak-perestat-revnovat","sozavisimost-kak-vyyti","lichnye-granicy-v-pare"]',
 'В начале отношений всё кажется идеальным и легким. Вы часами разговариваете, смеетесь и чувствуете абсолютную синхронизацию. Но со временем вы замечаете, что дистанция между вами начинает неуловимо расти. Ответы становятся короче, встречи реже, а эмоциональная вовлеченность падает. Ваш мозг мгновенно бьет тревогу, предполагая самое худшее: «Я больше не привлекателен». На самом деле, потеря интереса редко происходит из-за угасшей красоты или внезапной ненависти. Чаще всего это медленный процесс, в основе которого лежат тонкие поведенческие сдвиги. Эволюционно наш мозг стремится к безопасности, но влечение питается новизной. Когда отношения становятся слишком предсказуемыми, уровень дофамина — гормона предвкушения — неизбежно снижается. Партнер начинает отдаляться не из-за отсутствия любви, а из-за потери загадки.',
 '{"painPoint":"Вы пишете длинные сообщения и получаете в ответ сухие смайлы. Вы пытаетесь угодить, но партнер смотрит в телефон и словно не замечает вас.","essence":[{"title":"Суть за 30 секунд","text":"Потеря интереса — это следствие рутины и растворения личных границ. Ваш мозг привык к партнеру, и дофамин перестал выделяться. Чтобы вернуть влечение, нужно не давить на человека, а заново создать здоровую дистанцию и интригу."}],"microAction":"Отложите телефон на 3 часа. Займитесь делом, которое требует вашей полной концентрации вне дома.","checklist":["Перестал ли я навязывать своё общество?","Есть ли у меня хобби, не связанные с партнером?","Умею ли я спокойно переносить паузы в общении?"],"dialogue":[{"instead":"Ты меня больше не любишь, почему ты такой холодный?","try":"Я вижу, что тебе нужно время для себя. Я планирую провести выходные со своими друзьями, отдохни пока.","why":"Показывает уважение к пространству партнера и собственную автономность."}],"twoSides":{"firstTitle":"Если дать пространство","firstItems":["Партнер чувствует свободу","Сам сокращает дистанцию","Влечение восстанавливается"],"secondTitle":"Если давить","secondItems":["Отстранение усиливается","Обнажается кризис несовместимости","Отношения разрушаются"],"bridge":"Пространство — не угроза отношениям, а их условие."},"visualMetaphor":{"title":"","description":""}}',
 '[{"title":"Суть за 30 секунд","paragraphs":["Потеря интереса — это следствие рутины и растворения личных границ. Ваш мозг привык к партнеру, и дофамин перестал выделяться. Чтобы вернуть влечение, нужно не давить на человека, а заново создать здоровую дистанцию и интригу."]},{"title":"Точка боли","paragraphs":["Вы пишете длинные сообщения и получаете в ответ сухие смайлы. Вы пытаетесь угодить, но партнер смотрит в телефон и словно не замечает вас."]},{"title":"Почему это происходит","paragraphs":["Эффект нейрональной адаптации и слияние. Мозг экономит энергию на том, что стало полностью безопасным и понятным. Отсутствие риска и новизны выключает систему вознаграждения.","Огромную роль играет так называемое слияние. Если вы полностью подстраиваетесь под человека, теряя свои границы, вы лишаете его возможности скучать по вам. Ваша постоянная, стопроцентная доступность воспринимается нервной системой как отсутствие вызова."]},{"title":"Что обычно советуют неправильно","paragraphs":["Начни контролировать его телефон. Устрой истерику, чтобы показать свои чувства. Старайся быть для него идеальной во всем.","Эти советы усиливают тревогу и слияние — именно то, что убивает влечение."]},{"title":"Что действительно помогает","paragraphs":["Восстановление собственной автономности. Партнеру нужно дать пространство, в котором он сможет почувствовать ваше отсутствие.","Вернитесь к своим интересам, друзьям и целям. Живите своей жизнью параллельно с отношениями."]},{"title":"Микро-действие на 5 минут","paragraphs":["Отложите телефон на 3 часа. Займитесь делом, которое требует вашей полной концентрации вне дома.","Это не игра в недоступность. Это возвращение себе своей жизни."]},{"title":"Конструктор диалогов","paragraphs":["Вместо «Ты меня не замечаешь» — «Я вижу, что тебе нужно время для себя. Я планирую провести выходные со своими друзьями, отдохни пока».","Такой ответ убирает давление и показывает вашу независимость."]},{"title":"Сценарии 50/50","paragraphs":["Либо партнер чувствует свободу и сам сокращает дистанцию.","Либо отстранение продолжается, обнажая более глубокий кризис несовместимости."]},{"title":"Чек-лист самопроверки","paragraphs":["Перестал ли я навязывать своё общество? Есть ли у меня хобби, не связанные с партнером? Умею ли я спокойно переносить паузы в общении?"]},{"title":"Пример из жизни","paragraphs":["Марина замечала, что муж всё реже приходил домой сразу после работы. Вместо того чтобы встречать его расспросами, она начала ходить на вечерние занятия йогой. Через три недели муж сам предложил устроить совместный ужин вне дома."]},{"title":"Исследования, модели и экспертные основания","paragraphs":["Исследования Хелен Фишер (нейробиолог, Университет Ратгерса) показывают: дофаминовая система влечения активируется на новизну и непредсказуемость.","Эффект «оптимального расстояния» описан в работах Эстер Перель: интимность требует не слияния, а разумного пространства между партнёрами.","Теория адаптации Шломо Бреннера объясняет, как привыкание снижает эмоциональную реакцию на знакомые стимулы."]},{"title":"Когда нужна помощь специалиста","paragraphs":["Если отдаление превращается в тотальный бойкот (игнорирование неделями) и вызывает у вас панические атаки.","Если вы полностью потеряли ощущение собственной ценности вне этих отношений."]},{"title":"Итог: что понять и сделать сегодня","paragraphs":["Запланируйте на вечер занятие исключительно для себя. Не рассказывайте партнеру в деталях, чем именно будете заниматься.","Потеря интереса — это не конец. Это сигнал о том, что паре нужна автономность."]}]',
 '[]',
 '{"title":"Проверьте себя","description":"Ответьте честно на несколько вопросов","questions":[{"question":"Как давно вы делали что-то только для себя?","options":["На этой неделе","Больше месяца назад","Не помню когда"]},{"question":"Что вы делаете, когда партнёр не отвечает?","options":["Жду спокойно","Начинаю беспокоиться","Пишу несколько раз подряд"]}],"resultNote":"Ваши ответы помогут понять, насколько вы зависите от реакции партнёра."}',
 10),

-- Статья 2: Почему мужчина отдаляется
('pochemu-muzhchina-otdalyaetsya',
 'Почему мужчина отдаляется',
 'Мужское отдаление — это биологическая реакция на стресс. Он изолируется, чтобы переварить эмоции без ощущения уязвимости. Давление в этот момент только отдалит его сильнее.',
 '2026-05-03',
 'runpsy-editorial-team',
 'male-female-psychology',
 '["мужчина","отдаление","стресс","пещера","кортизол"]',
 '8 мин',
 'Почему мужчина отдаляется: нейробиология мужского стресса | RunPsy',
 'Почему мужчина уходит в себя и молчит. Нейробиология мужского стресса и что делать партнёрше.',
 'published',
 'эмоциональный',
 'Оставьте его в покое до завтрашнего утра. Переключите фокус на свои физические потребности.',
 'Если мужчина изолируется месяцами, проявляет агрессию на бытовые просьбы или заглушает стресс алкоголем.',
 '["pochemu-partner-otdalyaetsya","trevozhnaya-privyazannost-v-otnosheniyah"]',
 'С самого детства общество учит мужчин решать проблемы в одиночку. Выражение страха или растерянности часто табуируется и приравнивается к слабости. Поэтому, когда мужчина сталкивается с сильным стрессом на работе или в отношениях, он редко просит о помощи. Вместо этого его нервная система включает защитный режим изоляции. Он может часами сидеть в гараже, играть в видеоигры или просто молчать, глядя в экран. Женщины часто принимают эту дистанцию на свой счет. Начинаются тревожные мысли о потере любви или наличии другой женщины. Попытки вызвать его на откровенный разговор лишь усугубляют ситуацию. Для перегруженного мужского мозга ваши вопросы звучат не как забота, а как новые требования.',
 '{"painPoint":"Вы пытаетесь спросить, как прошел его день, а он отвечает односложно и уходит в другую комнату. Вы чувствуете себя отвергнутой и ненужной.","essence":[{"title":"Суть за 30 секунд","text":"Мужское отдаление — это биологическая реакция на стресс (уход в «пещеру»). Он изолируется, чтобы переварить эмоции и снизить кортизол без ощущения уязвимости. Давление в этот момент только отдалит его сильнее."}],"microAction":"Принесите ему чай или кофе молча. Не задавайте вопросов. Просто покажите своё присутствие и уйдите заниматься своими делами.","checklist":["Оставляю ли я его в покое, когда он раздражен?","Отделяю ли я его усталость от отношения ко мне?","Есть ли у него легальное время на тишину?"],"dialogue":[{"instead":"Ты опять молчишь, что с тобой случилось?","try":"Я вижу, что ты перегружен. Я не буду тебя дергать. Если захочешь поговорить — я рядом.","why":"Снимает давление и активирует мужскую систему безопасности."}],"twoSides":{"firstTitle":"Если дать тишину","firstItems":["Восстанавливает ресурс","Возвращается тёплым","Сам инициирует разговор"],"secondTitle":"Если давить","secondItems":["Уходит глубже","Агрессия нарастает","Хроническое отстранение"],"bridge":"Мужская пещера — не отвержение, а способ выжить."},"visualMetaphor":{"title":"","description":""}}',
 '[{"title":"Суть за 30 секунд","paragraphs":["Мужское отдаление — это биологическая реакция на стресс (уход в «пещеру»). Он изолируется, чтобы переварить эмоции и снизить кортизол без ощущения уязвимости. Давление в этот момент только отдалит его сильнее."]},{"title":"Точка боли","paragraphs":["Вы пытаетесь спросить, как прошел его день, а он отвечает односложно и уходит в другую комнату. Вы чувствуете себя отвергнутой и ненужной."]},{"title":"Почему это происходит","paragraphs":["Алекситимия и реакция «замри». Мужской мозг под воздействием стресса отключает речевые центры и фокусируется на внутреннем энергосбережении. Любой внешний запрос считывается как атака.","Психика мужчины экономит ресурс префронтальной коры. Ему нужно время в «пещере», чтобы снизить уровень кортизола. Это молчание — попытка восстановить внутренний контроль, а не наказать вас."]},{"title":"Что обычно советуют неправильно","paragraphs":["Заставь его выговориться. Плачь, чтобы пробить его броню. Обидься и накажи его ответным молчанием.","Все эти советы усиливают его ощущение угрозы и заставляют уйти глубже."]},{"title":"Что действительно помогает","paragraphs":["Создание эмоционально безопасной тишины. Позвольте ему пережить стресс его собственным способом, не требуя вербальных отчетов.","Как только вы перестаете требовать ответа, его система безопасности успокаивается."]},{"title":"Микро-действие на 5 минут","paragraphs":["Принесите ему чай или кофе молча. Не задавайте вопросов. Просто покажите своё присутствие и уйдите заниматься своими делами.","Это невербальный сигнал: «Я здесь, но не давлю»."]},{"title":"Конструктор диалогов","paragraphs":["Вместо «Почему ты молчишь?» — «Я вижу, что ты перегружен. Я не буду тебя дергать. Если захочешь поговорить — я рядом».","Одна фраза — и давление снято."]},{"title":"Сценарии 50/50","paragraphs":["Либо он восстанавливает ресурс и возвращается к вам тёплым и включённым.","Либо его отстранение становится хроническим, перерастая в депрессию."]},{"title":"Чек-лист самопроверки","paragraphs":["Оставляю ли я его в покое, когда он раздражен? Отделяю ли я его усталость от отношения ко мне? Есть ли у него легальное время на тишину?"]},{"title":"Пример из жизни","paragraphs":["Ольга научилась замечать момент, когда муж «закрывается»: плечи напряжены, взгляд в одну точку. Она перестала задавать вопросы и начала просто оставлять рядом кружку чая. Через час муж сам приходил и рассказывал о своём дне."]},{"title":"Исследования, модели и экспертные основания","paragraphs":["Джон Готтман выявил паттерн «stonewalling» — эмоциональное отстранение как защитную реакцию на перегрузку.","Исследования Шелли Тейлор показывают: мужская реакция на стресс чаще «fight or flight», а не «tend and befriend».","Алекситимия (сложность с распознаванием эмоций) встречается у мужчин в 5 раз чаще, что объясняет трудности с вербализацией состояний."]},{"title":"Когда нужна помощь специалиста","paragraphs":["Если мужчина изолируется месяцами, проявляет агрессию на бытовые просьбы или заглушает стресс алкоголем.","Хроническое отстранение без периодов тепла — признак депрессии, требующей профессиональной помощи."]},{"title":"Итог: что понять и сделать сегодня","paragraphs":["Оставьте его в покое до завтрашнего утра. Переключите фокус на свои физические потребности (сон, ванна, книга).","Его молчание — не ваша вина. Это его способ справляться."]}]',
 '[]',
 '{"title":"Проверьте себя","description":"Как вы реагируете на мужское молчание?","questions":[{"question":"Что вы делаете, когда партнёр замолкает?","options":["Даю пространство","Начинаю расспрашивать","Обижаюсь и молчу в ответ"]},{"question":"Как долго вы можете терпеть тишину?","options":["Спокойно жду","Несколько часов","Не могу вынести"]}],"resultNote":"Ваша реакция на молчание формирует или разрушает безопасность в паре."}',
 11),

-- Статья 3: Почему женщина охладела
('pochemu-zhenshchina-okhladela',
 'Почему женщина охладела',
 'Женская холодность — это симптом выгорания от эмоционального обслуживания. Невозможно испытывать влечение к тому, для кого ты работаешь менеджером.',
 '2026-05-03',
 'runpsy-editorial-team',
 'male-female-psychology',
 '["женщина","выгорание","холодность","либидо","когнитивная нагрузка"]',
 '9 мин',
 'Почему женщина охладела: выгорание и эмоциональная нагрузка | RunPsy',
 'Почему женщина становится холодной в отношениях. Как эмоциональная перегрузка убивает влечение и что с этим делать.',
 'published',
 'эмоциональный',
 'Решите одну проблему по дому до того, как она успеет вас об этом попросить.',
 'Если холодность переходит в тотальную апатию ко всему (ангедония), нарушения сна и резкую потерю веса.',
 '["pochemu-partner-otdalyaetsya","lichnye-granicy-v-pare"]',
 'В современной культуре от женщины ожидают виртуозного менеджмента всех аспектов жизни семьи. Она должна помнить о графике прививок, оплате счетов и настроении каждого домочадца. Эта невидимая эмоциональная и когнитивная нагрузка истощает её ресурсы подчистую. Когда женщина превращается в круглосуточного опекуна, динамика пары неизбежно меняется. Её мозг физиологически не способен испытывать сексуальное влечение к партнеру, которого приходится контролировать или обслуживать. Возбуждение требует расслабления, лёгкости и потери контроля. Ни о каком расслаблении не может быть и речи, если её префронтальная кора перегружена задачами.',
 '{"painPoint":"Она раздражается от ваших прикосновений. Все разговоры сводятся к спискам покупок. Вы чувствуете, что живёте с соседкой-надзирательницей.","essence":[{"title":"Суть за 30 секунд","text":"Женская холодность — это симптом выгорания от эмоционального обслуживания. Невозможно испытывать влечение к тому, для кого ты работаешь менеджером. Чтобы вернуть тепло, необходимо снять с неё когнитивный груз."}],"microAction":"Возьмите одну бытовую зону (например, ужин или мытьё полов) и делайте это молча каждый день на протяжении недели.","checklist":["Часто ли я спрашиваю у неё, как сделать простые бытовые вещи?","Есть ли у неё час в день, когда она ни за кого не отвечает?","Вижу ли я в ней женщину, а не только администратора дома?"],"dialogue":[{"instead":"Ты сегодня опять недовольна, в чём дело?","try":"Сегодня вечером ты свободна. Я сам решу вопрос с ужином и детьми. Иди в спальню и отдыхай, тебя никто не тронет.","why":"Снимает когнитивную нагрузку без объяснений и переговоров."}],"twoSides":{"firstTitle":"Если снять нагрузку","firstItems":["Нервная система расслабляется","Возвращается тепло","Восстанавливается близость"],"secondTitle":"Если ничего не менять","secondItems":["Выгорание углубляется","Полная эмоциональная апатия","Отношения превращаются в сосуществование"],"bridge":"Влечение живёт там, где есть пространство для отдыха."},"visualMetaphor":{"title":"","description":""}}',
 '[{"title":"Суть за 30 секунд","paragraphs":["Женская холодность — это симптом выгорания от эмоционального обслуживания. Невозможно испытывать влечение к тому, для кого ты работаешь менеджером. Чтобы вернуть тепло, необходимо снять с неё когнитивный груз."]},{"title":"Точка боли","paragraphs":["Она раздражается от ваших прикосновений. Все разговоры сводятся к спискам покупок. Вы чувствуете, что живёте с соседкой-надзирательницей."]},{"title":"Почему это происходит","paragraphs":["Выгорание опекуна (Caretaker Burnout). Избыток ответственности переводит нервную систему в режим выживания. Репродуктивные и романтические функции мозга отключаются за ненадобностью.","Холодность в этом случае — не внезапно угасшая любовь. Это клиническое выгорание нервной системы. Она не стала черствой, она просто устала быть функцией."]},{"title":"Что обычно советуют неправильно","paragraphs":["Купи ей дорогое бельё. Попробуй обнять её силой. Упрекай в том, что она стала скучной.","Для истощённой психики любой сюрприз — это ещё одно событие, требующее эмоциональной реакции."]},{"title":"Что действительно помогает","paragraphs":["Делегирование ответственности «под ключ». Мужчина должен забирать задачи целиком, не спрашивая у неё инструкций по выполнению.","Спасти ситуацию может только радикальное перераспределение ответственности."]},{"title":"Микро-действие на 5 минут","paragraphs":["Возьмите одну бытовую зону (например, ужин или мытьё полов) и делайте это молча каждый день на протяжении недели.","Без вопросов, без уточнений, без отчётов."]},{"title":"Конструктор диалогов","paragraphs":["Вместо «Почему ты такая холодная?» — «Сегодня вечером ты свободна. Я сам решу вопрос с ужином и детьми. Иди в спальню и отдыхай, тебя никто не тронет».","Действие важнее слов."]},{"title":"Сценарии 50/50","paragraphs":["Либо её нервная система расслабляется, и к ней возвращается тепло.","Либо она настолько привыкла к контролю, что начнёт злиться на ваши «неправильные» действия."]},{"title":"Чек-лист самопроверки","paragraphs":["Часто ли я спрашиваю у неё, как сделать простые бытовые вещи? Есть ли у неё час в день, когда она ни за кого не отвечает? Вижу ли я в ней женщину, а не только администратора дома?"]},{"title":"Пример из жизни","paragraphs":["Андрей три недели подряд молча готовил ужин и укладывал детей, не спрашивая жену о деталях. На четвёртой неделе она впервые за месяцы сама предложила провести вечер вдвоём."]},{"title":"Исследования, модели и экспертные основания","paragraphs":["Понятие «ментальная нагрузка» описано социологом Эммой (комикс «You Should Have Asked»): невидимая работа по планированию семейной жизни лежит преимущественно на женщинах.","Исследования Эмили Нагоски («Burnout») показывают: женский стресс-цикл требует физического завершения (движение, смех, объятия), иначе кортизол не снижается.","Мозг не может одновременно находиться в режиме управления и режиме влечения — это физиологически несовместимые состояния."]},{"title":"Когда нужна помощь специалиста","paragraphs":["Если холодность переходит в тотальную апатию ко всему (ангедония), нарушения сна и резкую потерю веса.","Это признаки клинической депрессии, требующей медицинской помощи."]},{"title":"Итог: что понять и сделать сегодня","paragraphs":["Решите одну проблему по дому до того, как она успеет вас об этом попросить.","Не объявляйте об этом. Просто сделайте."]}]',
 '[]',
 '{"title":"Проверьте себя","description":"Как распределена нагрузка в вашей паре?","questions":[{"question":"Кто обычно помнит о бытовых задачах?","options":["Примерно поровну","В основном партнёрша","В основном я"]},{"question":"Сколько часов в неделю у неё есть только для себя?","options":["Несколько часов","Пару часов","Практически нет"]}],"resultNote":"Неравномерное распределение нагрузки — главная причина женского выгорания в паре."}',
 12),

-- Статья 4: Как пережить расставание
('kak-perezhit-rassavaniye',
 'Как пережить расставание',
 'Расставание — это синдром отмены. Мозг требует старого дофамина. Единственный путь к исцелению — полная изоляция и перестройка химических процессов мозга через новые действия.',
 '2026-05-03',
 'runpsy-editorial-team',
 'breakup-recovery',
 '["расставание","боль","дофамин","no contact","исцеление"]',
 '9 мин',
 'Как пережить расставание: нейробиология боли разрыва | RunPsy',
 'Как пережить расставание и не сломаться. Нейробиология боли разлуки и практические шаги к исцелению.',
 'published',
 'кризисный',
 'Заблокируйте номер бывшего партнера. Верните себе контроль над своим вниманием.',
 'Если боль не стихает более полугода, нарушен сон и появляются мысли о нежелании жить.',
 '["kak-otpustit-cheloveka","emocionalnoe-onemenie"]',
 'Расставание часто описывают как душевную рану, но наука смотрит на это жёстче. Разрыв отношений — это глубокий физиологический шок для всего организма. Ваш мозг внезапно лишается привычного источника дофамина и окситоцина. То, что вы чувствуете по ночам, — это реальная химическая ломка, сравнимая с отказом от тяжёлых наркотиков. Эволюция научила нас воспринимать потерю социальных связей как угрозу выживанию. Поэтому зоны мозга, отвечающие за физическую боль, активируются при расставании на полную мощность. Именно этот биологический страх толкает вас на унизительные попытки вернуть бывшего партнёра.',
 '{"painPoint":"Вы просыпаетесь в 3 часа ночи и судорожно проверяете его онлайн. Вы готовы унижаться и прощать всё, лишь бы услышать родной голос.","essence":[{"title":"Суть за 30 секунд","text":"Расставание — это синдром отмены. Мозг требует старого дофамина и заставляет вас идеализировать бывшего. Единственный путь к исцелению — полная изоляция и перестройка химических процессов мозга через новые действия."}],"microAction":"Уберите все подарки и совместные фото в коробку и спрячьте в дальний шкаф. С глаз долой — из нейронных путей вон.","checklist":["Отписан ли я от его соцсетей?","Остановлен ли мой поток жалоб друзьям на эту тему?","Заставляю ли я свой мозг решать новые, сложные задачи?"],"dialogue":[{"instead":"Мне так больно, я напишу ему ещё раз","try":"Мне сейчас больно не потому, что мы созданы друг для друга. Мне больно, потому что моя нервная система проходит детоксикацию.","why":"Переосмысление боли как физиологии снижает её интенсивность."}],"twoSides":{"firstTitle":"Если выдержать изоляцию","firstItems":["Через 3 месяца боль утихает","Нейронные пути перестраиваются","Появляется ресурс для новой жизни"],"secondTitle":"Если сорваться на контакт","secondItems":["Прогресс обнуляется","Боль возвращается с удвоенной силой","Выздоровление затягивается на годы"],"bridge":"Каждый день без контакта — шаг к свободе."},"visualMetaphor":{"title":"","description":""}}',
 '[{"title":"Суть за 30 секунд","paragraphs":["Расставание — это синдром отмены. Мозг требует старого дофамина и заставляет вас идеализировать бывшего. Единственный путь к исцелению — полная изоляция и перестройка химических процессов мозга через новые действия."]},{"title":"Точка боли","paragraphs":["Вы просыпаетесь в 3 часа ночи и судорожно проверяете его онлайн. Вы готовы унижаться и прощать всё, лишь бы услышать родной голос."]},{"title":"Почему это происходит","paragraphs":["Эффект угасания эмоций (Fading Affect Bias). Мозг стирает плохие воспоминания для защиты психики. Активируется передняя поясная извилина — центр физической боли, заставляющий тело страдать физически.","Попытки «остаться друзьями» лишь замедляют процесс детоксикации нервных путей. Каждый новый контакт работает как микродоза, запускающая процесс отвыкания с нуля."]},{"title":"Что обычно советуют неправильно","paragraphs":["Давай останемся друзьями. Следи за ним с фейковых аккаунтов. Выпей и напиши всё, что думаешь.","Всё это удлиняет боль и не даёт мозгу перестроиться."]},{"title":"Что действительно помогает","paragraphs":["Радикальный No Contact (Никаких контактов). Полное отключение визуальных и слуховых триггеров, связанных с человеком.","Чтобы выжить, необходимо признать: ваша боль имеет химическую природу. Вы не умираете от потери великой любви, ваше тело просто адаптируется к новым условиям."]},{"title":"Микро-действие на 5 минут","paragraphs":["Уберите все подарки и совместные фото в коробку и спрячьте в дальний шкаф. С глаз долой — из нейронных путей вон.","Это не слабость. Это нейрогигиена."]},{"title":"Конструктор диалогов","paragraphs":["Вместо очередного сообщения бывшему скажите себе: «Мне сейчас больно не потому, что мы созданы друг для друга. Мне больно, потому что моя нервная система проходит детоксикацию»."]},{"title":"Сценарии 50/50","paragraphs":["Либо вы выдерживаете изоляцию, и через 3 месяца боль утихает.","Либо вы срываетесь на контакт, обнуляя весь прогресс выздоровления."]},{"title":"Чек-лист самопроверки","paragraphs":["Отписан ли я от его соцсетей? Остановлен ли мой поток жалоб друзьям на эту тему? Заставляю ли я свой мозг решать новые, сложные задачи?"]},{"title":"Пример из жизни","paragraphs":["Катя удалила все фото с Максимом из телефона и отписалась от его страниц в первый же день. Первые две недели были невыносимы. На третьей неделе она записалась на курсы керамики. Через три месяца она с трудом вспоминала детали его лица."]},{"title":"Исследования, модели и экспертные основания","paragraphs":["МРТ-исследования Этан Кросс (Мичиганский университет): отвержение активирует те же зоны мозга, что и физическая боль.","Исследования Хелен Фишер показывают: любовь работает как кокаиновая зависимость в плане нейрохимии.","No Contact как терапевтическая практика описана в работах Сьюзан Андерсон («Путешествие от отвержения к связи»)."]},{"title":"Когда нужна помощь специалиста","paragraphs":["Если боль не стихает более полугода, нарушен сон и появляются мысли о нежелании жить.","Это признаки тяжёлой депрессии, требующей немедленной профессиональной помощи."]},{"title":"Итог: что понять и сделать сегодня","paragraphs":["Заблокируйте номер бывшего партнёра. Верните себе контроль над своим вниманием.","Каждый день без контакта — это победа вашей нервной системы."]}]',
 '[]',
 '{"title":"Проверьте себя","description":"Где вы сейчас в процессе расставания?","questions":[{"question":"Как давно произошло расставание?","options":["Меньше месяца","1–3 месяца","Больше полугода"]},{"question":"Поддерживаете ли вы контакт с бывшим?","options":["Нет, полностью заблокирован","Иногда переписываемся","Общаемся регулярно"]}],"resultNote":"Чем меньше контактов — тем быстрее восстанавливается нервная система."}',
 13),

-- Статья 5: Как отпустить человека
('kak-otpustit-cheloveka',
 'Как отпустить человека',
 'То, что вы не можете отпустить — это не любовь, а одержимость (лимеренция). Отпустить человека можно только деконструировав фантазию о нём.',
 '2026-05-03',
 'runpsy-editorial-team',
 'breakup-recovery',
 '["лимеренция","одержимость","отпустить","зависимость","фантазия"]',
 '8 мин',
 'Как отпустить человека: лимеренция и эмоциональная зависимость | RunPsy',
 'Почему так сложно отпустить человека и как это сделать. Разбираем лимеренцию и переменное подкрепление.',
 'published',
 'эмоциональный',
 'Прекратите инициировать любой контакт. Потратьте освободившуюся энергию на рабочую задачу.',
 'Если зависимость доводит до сталкинга (слежки), клинического недосыпа или парализует вашу карьеру.',
 '["kak-perezhit-rassavaniye","emocionalnoe-onemenie","kak-ponyat-lyubov-ili-zavisimost"]',
 'Вся индустрия поп-культуры убеждает нас, что настоящая любовь должна сносить крышу. Бессонные ночи, невозможность думать о ком-то другом и постоянное ожидание сообщений продаются нам как эталон романтики. Однако с точки зрения доказательной психологии это не любовь. Это лимеренция — тяжёлое состояние навязчивой эмоциональной зависимости. Здоровая любовь базируется на окситоцине, который даёт чувство покоя, доверия и безопасности. Лимеренция же работает исключительно на адреналине и дофамине, гормонах стресса и предвкушения.',
 '{"painPoint":"Ваше настроение зависит исключительно от того, ответил ли он на сообщение. Вы придумываете оправдания его холодному поведению и ждёте чуда.","essence":[{"title":"Суть за 30 секунд","text":"То, что вы не можете отпустить — это не любовь, а одержимость (лимеренция). Вы зависите от эмоциональных качелей и дофаминовых всплесков. Отпустить человека можно только деконструировав фантазию о нём."}],"microAction":"Напишите список фактов. Перечислите три конкретных поступка, которые показывают его равнодушие. Перечитывайте при каждом приступе иллюзий.","checklist":["Оцениваю ли я его по поступкам, а не по обещаниям?","Перестал ли я перекладывать на него ответственность за своё счастье?","Осознаю ли я разницу между спокойной любовью и тревожной химией?"],"dialogue":[{"instead":"Может, он просто занят? Может, ещё позвонит?","try":"Я скучаю не по нему, а по тому, каким он мог бы быть. Моя фантазия не имеет ничего общего с реальностью.","why":"Разделение реального человека и фантазии о нём разрушает иллюзию."}],"twoSides":{"firstTitle":"Если разрушить иллюзию","firstItems":["Психика освобождается","Появляются силы на реальную жизнь","Открывается возможность встретить настоящую близость"],"secondTitle":"Если продолжать ждать","secondItems":["Жестокое финальное отвержение","Годы потраченного времени","Разрушение самооценки"],"bridge":"Вы скучаете не по человеку, а по версии себя рядом с ним."},"visualMetaphor":{"title":"","description":""}}',
 '[{"title":"Суть за 30 секунд","paragraphs":["То, что вы не можете отпустить — это не любовь, а одержимость (лимеренция). Вы зависите от эмоциональных качелей и дофаминовых всплесков. Отпустить человека можно только деконструировав фантазию о нём."]},{"title":"Точка боли","paragraphs":["Ваше настроение зависит исключительно от того, ответил ли он на сообщение. Вы придумываете оправдания его холодному поведению и ждёте чуда."]},{"title":"Почему это происходит","paragraphs":["Переменное подкрепление (Intermittent Reinforcement). Непредсказуемая награда вызывает сильнейшую аддикцию. Мозг впадает в навязчивое состояние, путая страх отвержения со страстью.","Вы влюбляетесь не в реального человека, а в иллюзию, которую сами для него создали. Ваш мозг использует объект страсти как внешний костыль для регуляции собственной самооценки."]},{"title":"Что обычно советуют неправильно","paragraphs":["Докажи ему свою преданность. Ищи тайные знаки в его поведении. Верь, что ваша любовь всё победит.","Эти советы поддерживают иллюзию и усиливают зависимость."]},{"title":"Что действительно помогает","paragraphs":["Смещение фокуса с потенциала человека на его реальные действия. Опора на факты. Жёсткое признание собственной зависимости.","Осознайте: вы скучаете не по чувству собственной значимости, а не по этому человеку."]},{"title":"Микро-действие на 5 минут","paragraphs":["Напишите список фактов. Перечислите три конкретных поступка, которые показывают его равнодушие. Перечитывайте при каждом приступе иллюзий.","Факты — единственное противоядие от фантазии."]},{"title":"Конструктор диалогов","paragraphs":["Вместо поиска оправданий его поведению скажите себе: «Я скучаю не по нему, а по тому, каким он мог бы быть. Моя фантазия не имеет ничего общего с реальностью»."]},{"title":"Сценарии 50/50","paragraphs":["Либо вы разрушаете иллюзию и освобождаете свою психику.","Либо продолжаете ждать, пока вас не сломает жестокое, финальное отвержение."]},{"title":"Чек-лист самопроверки","paragraphs":["Оцениваю ли я его по поступкам, а не по обещаниям? Перестал ли я перекладывать на него ответственность за своё счастье? Осознаю ли я разницу между спокойной любовью и тревожной химией?"]},{"title":"Пример из жизни","paragraphs":["Вика провела три месяца в ожидании звонка от Артёма, который «был занят». Когда она выписала на бумагу все его конкретные действия за полгода, список оказался пустым. Эта бумага стала её якорем в реальность."]},{"title":"Исследования, модели и экспертные основания","paragraphs":["Лимеренция описана психологом Дороти Теннов в книге «Love and Limerence» (1979) — навязчивое состояние, отличное от зрелой любви.","Переменное подкрепление (Skinner) — мощнейший механизм формирования зависимости, используемый в казино и нездоровых отношениях.","Исследования показывают: уверенность в себе — главный предиктор способности отпустить нездоровые отношения."]},{"title":"Когда нужна помощь специалиста","paragraphs":["Если зависимость доводит до сталкинга (слежки), клинического недосыпа или парализует вашу карьеру.","Это признаки зависимого расстройства личности, требующего терапии."]},{"title":"Итог: что понять и сделать сегодня","paragraphs":["Прекратите инициировать любой контакт. Потратьте освободившуюся энергию на рабочую задачу.","Каждый час без мыслей о нём — ваш личный рекорд."]}]',
 '[]',
 '{"title":"Проверьте себя","description":"Лимеренция или любовь?","questions":[{"question":"Как вы себя чувствуете, когда он не отвечает?","options":["Немного беспокоюсь","Сильно тревожусь","Паникую"]},{"question":"Оцениваете ли вы его по реальным поступкам?","options":["Да, опираюсь на факты","Стараюсь, но сложно","Нет, верю в его потенциал"]}],"resultNote":"Чем сильнее тревога при молчании — тем больше лимеренции и меньше любви."}',
 14),

-- Статья 6: Токсичные отношения: 12 признаков
('toksichnye-otnosheniya-priznaki',
 'Токсичные отношения: 12 признаков',
 'Токсичные отношения — это медленное разрушение вашей личности. Манипуляции, газлайтинг и изоляция превращают вас в заложника.',
 '2026-05-03',
 'runpsy-editorial-team',
 'relationships',
 '["токсичность","газлайтинг","манипуляция","абьюз","границы"]',
 '10 мин',
 'Токсичные отношения: 12 признаков абьюза | RunPsy',
 'Как распознать токсичные отношения. 12 признаков газлайтинга, манипуляций и эмоционального насилия.',
 'published',
 'кризисный',
 'Напишите список из 3 вещей, которые вы больше никогда не позволите делать в свой адрес.',
 'Когда психологическое насилие перерастает в физическое, или вы полностью потеряли контроль над финансами.',
 '["lichnye-granicy-v-pare","sozavisimost-kak-vyyti","kak-vosstanovit-doverie-posle-lzhi"]',
 'Токсичность в отношениях редко начинается с громких скандалов или открытого насилия. Обычно она проникает в вашу жизнь незаметно, маскируясь под заботу или страсть. Партнёр постепенно начинает стирать ваши личные границы через мелкие замечания и шутки. Вы начинаете сомневаться в собственной адекватности, что в психологии называется газлайтингом. Ваша нервная система переходит в режим хронической гипербдительности. Вы тщательно подбираете слова, чтобы не спровоцировать очередную вспышку недовольства. Этот постоянный стресс приводит к выбросу кортизола, который разрушает ваше физическое здоровье.',
 '{"painPoint":"Вы постоянно извиняетесь, даже если не виноваты. После разговора с партнёром вы чувствуете себя опустошённым и глупым.","essence":[{"title":"Суть за 30 секунд","text":"Токсичные отношения — это медленное разрушение вашей личности. Манипуляции, газлайтинг и изоляция превращают вас в заложника. Спасение начинается с доверия к собственным ощущениям дискомфорта."}],"microAction":"Правило «Серый камень». Отвечайте на провокации партнёра односложно, скучно и без эмоций, чтобы лишить его подпитки.","checklist":["Боюсь ли я реакции партнёра на мои обычные слова?","Оправдываю ли я его грубость усталостью?","Скрываю ли я от близких правду о наших отношениях?"],"dialogue":[{"instead":"Ладно, прости, я больше не буду","try":"Я не буду продолжать этот разговор, пока ты не изменишь тон. Мы вернёмся к этому позже.","why":"Устанавливает границу без эскалации конфликта."}],"twoSides":{"firstTitle":"Если применить метод серого камня","firstItems":["Абьюзер теряет интерес","Провокации снижаются","Вы сохраняете энергию"],"secondTitle":"Если продолжать реагировать эмоционально","secondItems":["Манипуляции усиливаются","Ваша энергия истощается","Контроль над вами растёт"],"bridge":"Ваши эмоции — его топливо. Перекройте подачу."},"visualMetaphor":{"title":"","description":""}}',
 '[{"title":"Суть за 30 секунд","paragraphs":["Токсичные отношения — это медленное разрушение вашей личности. Манипуляции, газлайтинг и изоляция превращают вас в заложника. Спасение начинается с доверия к собственным ощущениям дискомфорта."]},{"title":"Точка боли","paragraphs":["Вы постоянно извиняетесь, даже если не виноваты. После разговора с партнёром вы чувствуете себя опустошённым и глупым."]},{"title":"Почему это происходит","paragraphs":["Эмоциональное обесценивание и изоляция. Абьюзер ломает вашу внутреннюю опору, чтобы получить абсолютный контроль. Амигдала перегружается страхом.","Мозг адаптируется к токсичной среде, нормализуя эмоциональное насилие. Вам начинает казаться, что проблема кроется в вашем несовершенстве."]},{"title":"Что обычно советуют неправильно","paragraphs":["Попытайся понять его травмы детства. Будь мудрее и промолчи. Спаси его своей любовью.","Понимание чужих травм — не ваша ответственность. Ваша безопасность — ваша ответственность."]},{"title":"Что действительно помогает","paragraphs":["Установка жёстких границ. Документирование реальности (запись фактов, чтобы избежать газлайтинга). Восстановление связей с друзьями.","12 признаков токсичности: постоянная критика, газлайтинг, изоляция, контроль финансов, эмоциональные качели, обесценивание, манипуляция виной, игнорирование границ, ревность как контроль, публичные унижения, угрозы, непредсказуемые вспышки гнева."]},{"title":"Микро-действие на 5 минут","paragraphs":["Правило «Серый камень». Отвечайте на провокации партнёра односложно, скучно и без эмоций, чтобы лишить его подпитки.","«Ладно», «Возможно», «Мне нужно подумать» — ваш новый словарь."]},{"title":"Конструктор диалогов","paragraphs":["Вместо извинений — «Я не буду продолжать этот разговор, пока ты не изменишь тон. Мы вернёмся к этому позже».","Спокойно. Чётко. Без объяснений."]},{"title":"Сценарии 50/50","paragraphs":["Либо абьюзер теряет интерес из-за отсутствия эмоций.","Либо усиливает агрессию, что становится сигналом к немедленному побегу."]},{"title":"Чек-лист самопроверки","paragraphs":["Боюсь ли я реакции партнёра на мои обычные слова? Оправдываю ли я его грубость усталостью? Скрываю ли я от близких правду о наших отношениях?"]},{"title":"Пример из жизни","paragraphs":["Лена три года считала себя «слишком чувствительной», потому что муж называл её обиды выдумкой. Когда подруга показала ей список признаков газлайтинга, она узнала в нём каждый пункт. Это стало началом её пути к выходу."]},{"title":"Исследования, модели и экспертные основания","paragraphs":["Концепция газлайтинга описана психологом Робином Стерном в книге «The Gaslight Effect».","Цикл насилия Ленор Уокер: напряжение → инцидент → примирение → спокойствие. Понимание цикла помогает не принять «медовый месяц» за исцеление.","Метод «Серый камень» разработан анонимным автором для защиты от нарциссических манипуляций."]},{"title":"Когда нужна помощь специалиста","paragraphs":["Когда психологическое насилие перерастает в физическое, или вы полностью потеряли контроль над финансами.","В России работает телефон доверия: 8-800-2000-122 (бесплатно)."]},{"title":"Итог: что понять и сделать сегодня","paragraphs":["Напишите список из 3 вещей, которые вы больше никогда не позволите делать в свой адрес.","Доверяйте своим ощущениям дискомфорта. Они — ваша система защиты."]}]',
 '[]',
 '{"title":"Проверьте себя","description":"Есть ли в ваших отношениях признаки токсичности?","questions":[{"question":"Часто ли вы извиняетесь, не понимая за что?","options":["Нет","Иногда","Постоянно"]},{"question":"Чувствуете ли вы страх перед реакцией партнёра?","options":["Нет","Иногда","Часто"]}],"resultNote":"Два «часто» — сигнал обратиться за профессиональной поддержкой."}',
 15),

-- Статья 9: Что делать после измены
('chto-delat-posle-izmeny',
 'Что делать после измены',
 'Измена вызывает шок, сопоставимый с ПТСР. Логика отключена. Первое правило: не принимать быстрых решений. Нужно физически дистанцироваться и стабилизировать нервную систему.',
 '2026-05-03',
 'runpsy-editorial-team',
 'crises-and-breakups',
 '["измена","предательство","ПТСР","доверие","кризис"]',
 '9 мин',
 'Что делать после измены: первые шаги к восстановлению | RunPsy',
 'Что делать, если партнёр изменил. Нейробиология шока от измены и пошаговый план восстановления.',
 'published',
 'кризисный',
 'Выпейте стакан воды, примите контрастный душ и постарайтесь заснуть. Сегодня не время для решений.',
 'Если флешбэки и панические атаки не дают вам базово функционировать (есть, спать, работать).',
 '["kak-vosstanovit-doverie-posle-lzhi","kak-perezhit-rassavaniye","toksichnye-otnosheniya-priznaki"]',
 'Измена партнёра — это травма, которая разрушает фундаментальную картину вашего мира. Нейробиологически реакция на неверность часто идентична посттравматическому стрессовому расстройству (ПТСР). Мозг внезапно осознаёт, что человек, обеспечивавший вашу безопасность, стал главным источником боли. Возникает острый когнитивный диссонанс, с которым психика не может справиться. Вас накрывают флешбэки, навязчивые образы и приступы неконтролируемой паники. В этот период префронтальная кора, отвечающая за логику, практически полностью отключается. Именно поэтому в первые недели после измены категорически нельзя принимать судьбоносные решения.',
 '{"painPoint":"Вас трясёт. Вы маниакально пытаетесь узнать все детали измены, расспрашивая партнёра, и тем самым режете себя без ножа.","essence":[{"title":"Суть за 30 секунд","text":"Измена вызывает шок, сопоставимый с ПТСР. Логика отключена. Первое правило: не принимать быстрых решений. Нужно физически дистанцироваться и стабилизировать нервную систему."}],"microAction":"Правило «Стоп-информация». Запретите себе задавать вопросы о любовнике/любовнице. Эта информация не поможет вам исцелиться.","checklist":["Сплю ли я минимум 6 часов в сутки?","Перестал ли я винить себя за чужой поступок?","Взял ли я паузу в общении с предавшим?"],"dialogue":[{"instead":"Расскажи мне всё, я должна знать детали","try":"Я в шоке. Мне нужно время и дистанция. Я не готова обсуждать наше будущее прямо сейчас.","why":"Защищает от дополнительной травматизации через детали."}],"twoSides":{"firstTitle":"После паузы и восстановления","firstItems":["Решение строить отношения с чистого листа","Осознанный выбор, а не реакция шока","Возможность настоящего прощения"],"secondTitle":"Если не взять паузу","secondItems":["Решение принято в состоянии аффекта","Либо поспешный развод, либо поспешное прощение","Ни то ни другое не исцеляет"],"bridge":"Пауза — не слабость. Это условие мудрого решения."},"visualMetaphor":{"title":"","description":""}}',
 '[{"title":"Суть за 30 секунд","paragraphs":["Измена вызывает шок, сопоставимый с ПТСР. Логика отключена. Первое правило: не принимать быстрых решений. Нужно физически дистанцироваться и стабилизировать нервную систему."]},{"title":"Точка боли","paragraphs":["Вас трясёт. Вы маниакально пытаетесь узнать все детали измены, расспрашивая партнёра, и тем самым режете себя без ножа."]},{"title":"Почему это происходит","paragraphs":["Амигдалярный захват и когнитивный диссонанс. Картина мира рухнула. Нервная система перегружена кортизолом и ищет спасения в контроле над информацией.","Первое побуждение — выяснить все болезненные детали измены — это ошибка травмированного мозга. Пытаясь обрести контроль над ситуацией, вы лишь наносите себе дополнительные раны."]},{"title":"Что обычно советуют неправильно","paragraphs":["Сразу подавай на развод. Измени в ответ, чтобы восстановить баланс. Забудь ради сохранения семьи.","Все эти советы игнорируют острую фазу шока, в которой нет места рациональным решениям."]},{"title":"Что действительно помогает","paragraphs":["Физическая пауза. Радикальный фокус на себе. Полное исключение партнёра из процесса вашей первичной эмоциональной стабилизации.","Ваш партнёр в этот момент не может быть вашим терапевтом или утешителем."]},{"title":"Микро-действие на 5 минут","paragraphs":["Правило «Стоп-информация». Запретите себе задавать вопросы о любовнике/любовнице. Эта информация не поможет вам исцелиться.","Каждый новый «болезненный факт» — это ещё один удар по вашей нервной системе."]},{"title":"Конструктор диалогов","paragraphs":["Вместо расспросов о деталях — «Я в шоке. Мне нужно время и дистанция. Я не готова обсуждать наше будущее прямо сейчас».","Это не конец разговора. Это начало вашего восстановления."]},{"title":"Сценарии 50/50","paragraphs":["Либо после паузы вы решаете строить отношения с чистого листа.","Либо понимаете, что склеить разбитое невозможно, и экологично расходитесь."]},{"title":"Чек-лист самопроверки","paragraphs":["Сплю ли я минимум 6 часов в сутки? Перестал ли я винить себя за чужой поступок? Взял ли я паузу в общении с предавшим?"]},{"title":"Пример из жизни","paragraphs":["Света узнала об измене мужа в пятницу вечером. Вместо немедленного решения о разводе она уехала к маме на выходные. Три дня тишины позволили ей выйти из состояния шока. Решение она приняла через месяц — взвешенно и без сожалений."]},{"title":"Исследования, модели и экспертные основания","paragraphs":["Исследования Джейн Гудолл (терапевт) показывают: 70% пар, прошедших терапию после измены, называют отношения более зрелыми, чем до неё.","Нейровизуализация подтверждает: реакция на измену активирует те же зоны, что и физическая травма.","Модель «информационного стоп-сигнала» применяется в травматерапии для предотвращения вторичной травматизации."]},{"title":"Когда нужна помощь специалиста","paragraphs":["Если флешбэки и панические атаки не дают вам базово функционировать (есть, спать, работать).","Это признаки острого стрессового расстройства, требующего профессиональной помощи."]},{"title":"Итог: что понять и сделать сегодня","paragraphs":["Выпейте стакан воды, примите контрастный душ и постарайтесь заснуть. Сегодня не время для решений.","Чужое предательство — это характеристика предателя, а не показатель вашей ущербности."]}]',
 '[]',
 '{"title":"Проверьте себя","description":"Где вы сейчас?","questions":[{"question":"Сколько времени прошло с момента измены?","options":["Меньше недели","1–4 недели","Больше месяца"]},{"question":"Приняли ли вы уже решение о будущем отношений?","options":["Нет, жду","Ещё не решил(а)","Да, уже решил(а)"]}],"resultNote":"Решение, принятое в первые две недели после измены — почти всегда решение из состояния шока, а не из ясности."}',
 16)

